  "schemaVersion": 3,
  "arcId": "arc_1_foundation_of_mud",
  "startChapter": 1,
  "endChapter": 30,
  "direction": "Chứng minh sức mạnh của bùn sinh mệnh qua việc vá đập nước, sau đó hợp nhất ba phe phái để xây dựng mái hiên chung đầu tiên chống bão tro.",
  "terminalChange": "Khu định cư chuyển từ lều bạt cá nhân sang sở hữu một công trình kiên cố chung; Kian từ thợ vô danh trở thành người nắm giữ quyền lực phân phối không gian sống và luật bảo trì.",
  "activeConflicts": [
    {
      "id": "conflict_khal_labor",
      "actorIds": [
        "char_kian",
        "char_khal"
      ],
      "objective": "Tranh giành quyền ưu tiên sử dụng không gian trong mái hiên chung.",
      "leverage": "Khal kiểm soát sức lao động của phu tro, có thể làm đứt gãy dây chuyền đắp bùn khiến mẻ bùn hỏng.",
      "nextMove": "Khal ra lệnh cho phu tro đình công giữa chừng khi mẻ bùn đang trộn để ép Kian nhượng bộ chia phần đất lớn nhất."
    },
    {
      "id": "conflict_rac_moss",
      "actorIds": [
        "char_kian",
        "char_rac"
      ],
      "objective": "Định giá lại sợi rêu xanh bạc khi nhu cầu xây dựng tăng vọt.",
      "leverage": "Lão Rạc độc quyền nguồn cung cấp rêu, nắm giữ sinh mạng của công trình và sự an toàn của thợ rêu.",
      "nextMove": "Lão Rạc giảm lượng rêu giao nộp, yêu cầu đổi lấy phần nước lớn hơn từ đập vừa sửa để bù đắp rủi ro khai thác."
    },
    {
      "id": "conflict_maintenance",
      "actorIds": [
        "char_kian",
        "char_balao"
      ],
      "objective": "Thiết lập ý thức và trách nhiệm bảo trì công trình chung.",
      "leverage": "Bà Lão có uy tín để ép người dân tuân thủ, nhưng người dân lại lười biếng và thiếu hiểu biết về đặc tính nhả độc của bùn.",
      "nextMove": "Bà Lão phải đứng ra phân xử và hỗ trợ Kian ban hành luật bảo trì khi một mảng tường nhả tro độc do không được quét dịch rêu."
    }
  ],
  "duePromiseIds": [
    "prom_dam"
  ],
  "progressionBudget": [
    {
      "signal": "Số lượng người tham gia dây chuyền đắp bùn",
      "requiredChange": "Từ 1 mình Kian lén lút vá đập lên đến hàng chục người từ cả ba phe phối hợp nhịp nhàng theo hiệu lệnh."
    },
    {
      "signal": "Kích thước và độ phức tạp của công trình",
      "requiredChange": "Từ một miếng vá nhỏ trên đập nước đến một mái hiên chung kiên cố đủ sức chứa toàn bộ người yếu thế trong làng."
    },
    {
      "signal": "Lượng tài nguyên dự trữ của lãnh địa",
      "requiredChange": "Nước ngọt dồi dào trở lại sau khi đập được vá, nhưng sợi rêu cạn kiệt nghiêm trọng, tạo tiền đề cho việc tìm nguồn rêu mới."
    }
  ]
}
